module top_module(
        input   wire [31:0]   op1,
        input   wire [31:0]   op2,
        input   wire [2:0]    operation,
        output  wire          res
    );reg unused_comp_res;

    always @ *
    case (operation)
        3'b000: unused_comp_res = (op1 ==  op2); 
        3'b010: unused_comp_res = (op1 >   op2);
        3'b101, 
        3'b110: unused_comp_res = (op1 <   op2);
        default: unused_comp_res = 1'bx;
    endcase

    assign res = unused_comp_res;

endmodule
